import { Component, OnInit, OnDestroy, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { Router, RouterModule } from '@angular/router';
import { interval, Subject as RxSubject, takeUntil } from 'rxjs';
import { CoursesService, StatsService, LiveSessionsService } from '../../services';
import { Course, PlatformStats, LiveSession, Subject } from '../../models';

@Component({
  selector: 'app-home',
  standalone: true,
  imports: [CommonModule, RouterModule],
  templateUrl: './home.component.html',
  styleUrls: ['./home.component.scss']
})
export class HomeComponent implements OnInit, OnDestroy {
  private router = inject(Router);
  private coursesService = inject(CoursesService);
  private statsService = inject(StatsService);
  private liveSessionsService = inject(LiveSessionsService);

  private destroy$ = new RxSubject<void>();

  featuredCourses: Course[] = [];
  stats: PlatformStats | null = null;
  upcomingSessions: LiveSession[] = [];
  currentSlideIndex = 0;
  currentYear = new Date().getFullYear();

  subjects: Subject[] = [
    { id: '1', name: 'Mathématiques', icon: '📐', color: 'blue' },
    { id: '2', name: 'Physique-Chimie', icon: '⚗️', color: 'purple' },
    { id: '3', name: 'Français', icon: '📚', color: 'pink' },
    { id: '4', name: 'Arabe', icon: '📖', color: 'amber' },
    { id: '5', name: 'Sciences Naturelles', icon: '🌿', color: 'green' },
    { id: '6', name: 'Histoire-Géographie', icon: '🌍', color: 'orange' },
    { id: '7', name: 'Informatique', icon: '💻', color: 'cyan' },
    { id: '8', name: 'Anglais', icon: '🇬🇧', color: 'red' }
  ];

  ngOnInit() {
    this.loadData();
    this.startCarousel();
  }

  ngOnDestroy() {
    this.destroy$.next();
    this.destroy$.complete();
  }

  private loadData() {
    // Load featured courses
    this.coursesService.getCourses().pipe(takeUntil(this.destroy$)).subscribe({
      next: (courses) => {
        this.featuredCourses = courses.slice(0, 6);
      },
      error: (error) => console.error('Error loading courses:', error)
    });

    // Load platform stats
    this.statsService.getPlatformStats().pipe(takeUntil(this.destroy$)).subscribe({
      next: (stats) => {
        this.stats = stats;
      },
      error: (error) => console.error('Error loading stats:', error)
    });

    // Load upcoming live sessions
    this.liveSessionsService.getLiveSessions(true).pipe(takeUntil(this.destroy$)).subscribe({
      next: (sessions) => {
        this.upcomingSessions = sessions.slice(0, 3);
      },
      error: (error) => console.error('Error loading sessions:', error)
    });
  }

  private startCarousel() {
    interval(4000).pipe(takeUntil(this.destroy$)).subscribe(() => {
      if (this.featuredCourses.length > 0) {
        this.currentSlideIndex = (this.currentSlideIndex + 1) % this.featuredCourses.length;
      }
    });
  }

  goToSlide(index: number) {
    this.currentSlideIndex = index;
  }

  nextSlide() {
    if (this.featuredCourses.length > 0) {
      this.currentSlideIndex = (this.currentSlideIndex + 1) % this.featuredCourses.length;
    }
  }

  prevSlide() {
    if (this.featuredCourses.length > 0) {
      this.currentSlideIndex = (this.currentSlideIndex - 1 + this.featuredCourses.length) % this.featuredCourses.length;
    }
  }

  exploreCourses() {
    this.router.navigate(['/courses']);
  }

  joinForFree() {
    this.router.navigate(['/register']);
  }

  enrollInCourse(courseId: string) {
    // Implementation would depend on auth state
    this.router.navigate(['/courses', courseId]);
  }

  joinSession(sessionId: string) {
    // Implementation would depend on auth state
    console.log('Join session:', sessionId);
  }

  trackByCourseId(index: number, course: Course): string {
    return course.id;
  }
}
<!-- Hero Section -->
<section class="relative min-h-screen flex items-center justify-center gradient-bg overflow-hidden">
  <div class="absolute inset-0 bg-black opacity-10"></div>
  <div class="relative z-10 text-center text-white px-4 animate-fade-in">
    <h1 class="text-5xl md:text-7xl font-bold mb-6 leading-tight">
      Learn Anything,<br>
      <span class="text-yellow-300">Anytime, Anywhere</span>
    </h1>
    <p class="text-xl md:text-2xl mb-8 opacity-90 max-w-3xl mx-auto">
      Join thousands of students and teachers in our comprehensive online learning platform
    </p>
    <div class="flex flex-col sm:flex-row gap-4 justify-center">
      <button (click)="exploreCourses()" class="btn-gradient bg-white text-primary-600 hover:bg-gray-100">
        Explore Courses
        <svg class="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M13 7l5 5m0 0l-5 5m5-5H6"/>
        </svg>
      </button>
      <button (click)="joinForFree()" class="btn-outline border-white text-white hover:bg-white hover:text-primary-600">
        Join for Free
        <svg class="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M18 9v3m0 0v3m0-3h3m-3 0h-3m-2-5a4 4 0 11-8 0 4 4 0 018 0zM3 20a6 6 0 0112 0v1H3v-1z"/>
        </svg>
      </button>
    </div>
  </div>

  <!-- Animated background elements -->
  <div class="absolute top-20 left-10 w-20 h-20 bg-white opacity-10 rounded-full animate-pulse-slow"></div>
  <div class="absolute bottom-20 right-10 w-32 h-32 bg-white opacity-10 rounded-full animate-bounce-slow"></div>
</section>

<!-- Featured Courses Carousel -->
<section class="py-16 px-4">
  <div class="max-w-7xl mx-auto">
    <div class="text-center mb-12">
      <h2 class="text-4xl font-bold text-gray-900 mb-4">Featured Courses</h2>
      <p class="text-xl text-gray-600">Discover our most popular courses</p>
    </div>

    <div class="relative carousel-container" *ngIf="featuredCourses.length > 0">
      <div class="carousel-track" [style.transform]="'translateX(-' + (currentSlideIndex * 100) + '%)'">
        <div *ngFor="let course of featuredCourses; trackBy: trackByCourseId" class="carousel-slide">
          <div class="max-w-4xl mx-auto">
            <div class="bg-white rounded-2xl shadow-xl overflow-hidden card-hover">
              <div class="md:flex">
                <div class="md:w-1/2">
                  <img [src]="course.thumbnail || '/api/placeholder/600/400'" 
                       [alt]="course.title" 
                       class="w-full h-64 md:h-full object-cover">
                </div>
                <div class="md:w-1/2 p-8">
                  <div class="flex items-center gap-2 mb-4">
                    <span class="px-3 py-1 bg-primary-100 text-primary-600 rounded-full text-sm font-medium">
                      {{ course.subjectName }}
                    </span>
                    <span *ngIf="course.isFree" class="px-3 py-1 bg-green-100 text-green-600 rounded-full text-sm font-medium badge-floating">
                      FREE
                    </span>
                  </div>
                  <h3 class="text-2xl font-bold text-gray-900 mb-3">{{ course.title }}</h3>
                  <p class="text-gray-600 mb-4 line-clamp-3">{{ course.description }}</p>
                  <div class="flex items-center justify-between mb-6">
                    <div class="text-sm text-gray-500">
                      <span class="font-medium">{{ course.teacherName }}</span> • {{ course.lessonCount }} lessons
                    </div>
                    <div class="flex items-center" *ngIf="course.rating">
                      <div class="flex text-yellow-400">
                        <svg class="w-5 h-5 fill-current" viewBox="0 0 20 20">
                          <path d="M10 15l-5.878 3.09 1.123-6.545L.489 6.91l6.572-.955L10 0l2.939 5.955 6.572.955-4.756 4.635 1.123 6.545z"/>
                        </svg>
                        <span class="ml-1 text-gray-700">{{ course.rating }}</span>
                      </div>
                    </div>
                  </div>
                  <button (click)="enrollInCourse(course.id)" 
                          class="w-full btn-gradient">
                    Enroll Now
                  </button>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>

      <!-- Carousel Controls -->
      <button (click)="prevSlide()" 
              class="absolute left-4 top-1/2 -translate-y-1/2 bg-white/80 hover:bg-white text-gray-800 rounded-full p-3 shadow-lg transition-all">
        <svg class="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M15 19l-7-7 7-7"/>
        </svg>
      </button>
      <button (click)="nextSlide()" 
              class="absolute right-4 top-1/2 -translate-y-1/2 bg-white/80 hover:bg-white text-gray-800 rounded-full p-3 shadow-lg transition-all">
        <svg class="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M9 5l7 7-7 7"/>
        </svg>
      </button>

      <!-- Dots Indicator -->
      <div class="flex justify-center mt-6 space-x-2">
        <button *ngFor="let course of featuredCourses; let i = index" 
                (click)="goToSlide(i)"
                [class]="i === currentSlideIndex ? 'w-8 bg-primary-600' : 'w-2 bg-gray-300'"
                class="h-2 rounded-full transition-all duration-300"></button>
      </div>
    </div>
  </div>
</section>

<!-- Stats Section -->
<section class="py-16 bg-gray-50">
  <div class="max-w-7xl mx-auto px-4">
    <div class="grid grid-cols-2 md:grid-cols-4 gap-8">
      <div class="text-center" *ngIf="stats">
        <div class="text-4xl md:text-5xl font-bold gradient-text counter-animation">
          {{ stats.totalStudents.toLocaleString() }}
        </div>
        <div class="text-gray-600 mt-2">Total Students</div>
      </div>
      <div class="text-center" *ngIf="stats">
        <div class="text-4xl md:text-5xl font-bold gradient-text counter-animation">
          {{ stats.totalCourses.toLocaleString() }}
        </div>
        <div class="text-gray-600 mt-2">Total Courses</div>
      </div>
      <div class="text-center" *ngIf="stats">
        <div class="text-4xl md:text-5xl font-bold gradient-text counter-animation">
          {{ stats.totalTeachers.toLocaleString() }}
        </div>
        <div class="text-gray-600 mt-2">Total Teachers</div>
      </div>
      <div class="text-center" *ngIf="stats">
        <div class="text-4xl md:text-5xl font-bold gradient-text counter-animation">
          {{ stats.upcomingLiveSessions.toLocaleString() }}
        </div>
        <div class="text-gray-600 mt-2">Upcoming Live Sessions</div>
      </div>
    </div>
  </div>
</section>

<!-- Subject Categories -->
<section class="py-16">
  <div class="max-w-7xl mx-auto px-4">
    <div class="text-center mb-12">
      <h2 class="text-4xl font-bold text-gray-900 mb-4">Browse by Subject</h2>
      <p class="text-xl text-gray-600">Find courses in your favorite subjects</p>
    </div>

    <div class="grid grid-cols-2 md:grid-cols-4 gap-6 stagger-animation">
      <div *ngFor="let subject of subjects" 
           class="bg-white rounded-xl p-6 text-center card-hover cursor-pointer"
           [class]="'bg-' + subject.color + '-50 border-2 border-' + subject.color + '-200'">
        <div class="text-4xl mb-3">{{ subject.icon }}</div>
        <h3 class="font-semibold text-gray-900">{{ subject.name }}</h3>
      </div>
    </div>
  </div>
</section>

<!-- Upcoming Live Sessions -->
<section class="py-16 bg-gray-50">
  <div class="max-w-7xl mx-auto px-4">
    <div class="text-center mb-12">
      <h2 class="text-4xl font-bold text-gray-900 mb-4">Upcoming Live Sessions</h2>
      <p class="text-xl text-gray-600">Join interactive live classes with expert teachers</p>
    </div>

    <div class="grid md:grid-cols-3 gap-6" *ngIf="upcomingSessions.length > 0">
      <div *ngFor="let session of upcomingSessions" 
           class="bg-white rounded-xl shadow-lg overflow-hidden card-hover">
        <div class="p-6">
          <div class="flex items-center justify-between mb-4">
            <span class="px-3 py-1 bg-red-100 text-red-600 rounded-full text-sm font-medium">
              {{ session.status }}
            </span>
            <span class="text-sm text-gray-500">
              {{ session.duration }}min
            </span>
          </div>
          <h3 class="text-xl font-bold text-gray-900 mb-2">{{ session.title }}</h3>
          <p class="text-gray-600 mb-4">{{ session.teacherName }}</p>
          <div class="text-sm text-gray-500 mb-4">
            {{ session.scheduledAt | date:'longDate' }} at {{ session.scheduledAt | date:'shortTime' }}
          </div>
          <button (click)="joinSession(session.id)" 
                  class="w-full btn-gradient">
            Join Session
          </button>
        </div>
      </div>
    </div>
  </div>
</section>

